function opportunity(l){return Math.round((100-l.seo)*(weights.gap/100)+l.scaleScore*(weights.scale/100))}
function priority(l){const o=opportunity(l);return l.critical||o>=60?"P1":o>=50?"P2":"P3"}
function pkg(l){if(l.critical)return l.scale==="A"?"Enterprise + Recovery":l.scale==="B"?"Growth + Recovery":"Local + Recovery";return l.scale==="A"?"اقتدار تهران":l.scale==="B"?"رشد منطقه‌ای":"پایه محلی"}
