function renderDashboard(){const p1=leads.filter(x=>priority(x)==="P1");$("#kpiLeads").textContent=fa(leads.length);$("#kpiP1").textContent=fa(p1.length);$("#kpiSeo").textContent=fa(Math.round(leads.reduce((a,b)=>a+b.seo,0)/leads.length));$("#kpiCritical").textContent=fa(leads.filter(x=>x.critical).length);const counts={A:0,B:0,C:0};leads.forEach(x=>counts[x.scale]++);$("#scaleBars").innerHTML=["A","B","C"].map(s=>`<div class="bar-row"><span>${scaleLabel(s)}</span><div class="bar-track"><div class="bar-fill" style="width:${counts[s]/leads.length*100}%"></div></div><b>${fa(counts[s])}</b></div>`).join("");const top=[...leads].sort((a,b)=>opportunity(b)-opportunity(a)).slice(0,5);$("#topLeads").innerHTML=top.map((l,i)=>`<div class="lead-mini" data-open="${esc(l.id)}"><span class="rank">${fa(i+1)}</span><div><strong>${esc(l.name)}</strong><small>${esc(l.issue)}</small></div><div class="score">${fa(opportunity(l))}<small>/100</small></div></div>`).join("");const critical=leads.filter(x=>x.critical).slice(0,4);$("#alerts").innerHTML=critical.map(l=>`<div class="alert critical" data-open="${esc(l.id)}"><i class="alert-dot"></i><div><strong>${esc(l.name)}</strong><p>${esc(l.tech)}</p></div></div>`).join("")||'<div class="empty">هشدار بحرانی وجود ندارد.</div>'}
function renderLeads(){const q=$("#leadSearch").value.trim().toLowerCase(),sf=$("#scaleFilter").value,pf=$("#priorityFilter").value,sort=$("#sortLeads").value;let list=leads.filter(l=>(!q||[l.name,l.area,l.services,l.website,l.phone,l.email,l.whatsapp,...(l.tags||[])].join(" ").toLowerCase().includes(q))&&(!sf||l.scale===sf)&&(!pf||priority(l)===pf));list.sort((a,b)=>sort==="seoAsc"?a.seo-b.seo:sort==="seoDesc"?b.seo-a.seo:sort==="name"?a.name.localeCompare(b.name,"fa"):opportunity(b)-opportunity(a));$("#leadRows").innerHTML=list.length?list.map(l=>`<tr data-open="${esc(l.id)}"><td><div class="clinic-name">${esc(l.name)}<small>${esc(l.area)}</small></div></td><td><span class="pill scale-${l.scale.toLowerCase()}">${scaleLabel(l.scale)}</span></td><td><div class="score-cell"><b>${fa(l.seo)}</b><span class="mini-track"><i style="width:${l.seo}%"></i></span></div></td><td><b>${fa(opportunity(l))}</b></td><td><span class="pill ${priority(l).toLowerCase()}">${priority(l)}</span></td><td>${esc(l.visibility)}</td><td dir="ltr" style="text-align:right">${esc(l.phone||"—")}${l.email?`<small style="display:block">${esc(l.email)}</small>`:""}${l.whatsapp?`<small style="display:block;color:#78e1d8">WA ${esc(l.whatsapp)}</small>`:""}</td><td>${esc(pkg(l))}</td><td><button class="btn sm">جزئیات</button></td></tr>`).join(""):'<tr><td class="empty" colspan="9">لیدی با این فیلتر پیدا نشد.</td></tr>'}
function openLead(id){const l=leads.find(x=>x.id===id);if(!l)return;currentLead=l;const web=l.website?(l.unsafe?`<span class="pill p1">لینک ناامن؛ باز نشود</span>`:`<a href="${esc(l.website)}" target="_blank" rel="noopener">${esc(l.website)}</a>`):"ندارد";$("#drawerBody").innerHTML=`<div class="detail-hero"><div style="display:flex;justify-content:space-between;gap:10px"><div><h2>${esc(l.name)}</h2><p>${esc(l.area)}</p></div><span class="pill ${priority(l).toLowerCase()}">${priority(l)}</span></div><div style="display:flex;gap:18px;margin-top:16px"><div><small>SEO</small><b style="display:block;font-size:22px">${fa(l.seo)}</b></div><div><small>فرصت</small><b style="display:block;font-size:22px">${fa(opportunity(l))}</b></div><div><small>مقیاس</small><b style="display:block;font-size:22px">${l.scale}</b></div></div></div><div class="detail-row"><b>وب‌سایت</b><span dir="ltr" style="text-align:right;word-break:break-all">${web}</span></div><div class="detail-row"><b>تماس عمومی</b><span dir="ltr" style="text-align:right">${esc(l.phone||"—")}</span></div><div class="detail-row"><b>ایمیل عمومی</b><span dir="ltr" style="text-align:right">${esc(l.email||"—")}</span></div><div class="detail-row"><b>WhatsApp عمومی</b><span dir="ltr" style="text-align:right">${esc(l.whatsapp||"—")}</span></div>${Array.isArray(l.tags)&&l.tags.length?`<div class="detail-row"><b>تگ‌ها</b><span>${l.tags.slice(0,12).map(x=>`#${esc(x)}`).join(" · ")}</span></div>`:""}<div class="detail-row"><b>خدمات</b><span>${esc(l.services)}</span></div><div class="detail-row"><b>خوشه هدف</b><span>${esc(l.target)}</span></div><div class="detail-box"><h4>یافته فنی</h4><p>${esc(l.tech)}</p></div><div class="detail-box"><h4>شکاف اصلی</h4><p>${esc(l.issue)}</p></div><div class="detail-box"><h4>برنامه ۹۰روزه</h4><p>${esc(l.plan)}</p></div><div class="detail-box"><h4>پکیج خودکار: ${esc(pkg(l))}</h4><p>${l.scale==="A"?"۸۰–۱۴۰ میلیون حق‌الزحمه + ۲۵–۶۰ میلیون رسانه":l.scale==="B"?"۴۵–۷۰ میلیون حق‌الزحمه + ۱۲–۲۵ میلیون رسانه":"۲۵–۴۰ میلیون حق‌الزحمه + ۵–۱۲ میلیون رسانه"} در ماه؛ قابل‌ویرایش و بدون تضمین رتبه مطلق.</p></div><div class="drawer-actions"><button class="btn primary" id="drawerMessage">ساخت پیام</button><button class="btn" id="drawerProposal">پیشنهاد PDF</button><button class="btn" id="drawerPartner">یافتن مجری</button>${l.website&&!l.unsafe?'<button class="btn" id="drawerAudit">ممیزی زنده</button><button class="btn" id="drawerAiSeo">تحلیل AI سئو</button>':''}<button class="btn" id="drawerCopy">کپی شماره</button></div>`;$("#drawer").classList.add("open");$("#drawerBackdrop").classList.add("open");$("#drawerMessage").onclick=()=>{go("outreach");$("#outreachLead").value=l.id;updateRecipient();generateMessage()};$("#drawerProposal").onclick=()=>{go("proposals");$("#proposalLead").value=l.id;applyProposalDefaults()};$("#drawerPartner").onclick=()=>{go("partners");$("#partnerLead").value=l.id;updatePartnerNeed()};if($("#drawerAudit"))$("#drawerAudit").onclick=()=>{go("audit");$("#auditUrls").value=l.website;runAudits()};if($("#drawerAiSeo"))$("#drawerAiSeo").onclick=()=>{go("audit");$("#aiSeoLead").value=l.id;$("#aiSeoUrl").value=l.website};$("#drawerCopy").onclick=()=>copyText(l.phone)}
function closeDrawer(){$("#drawer").classList.remove("open");$("#drawerBackdrop").classList.remove("open")}
$("#closeDrawer").onclick=closeDrawer;$("#drawerBackdrop").onclick=closeDrawer;document.addEventListener("click",e=>{const x=e.target.closest("[data-open]");if(x)openLead(x.dataset.open)});
["leadSearch","scaleFilter","priorityFilter","sortLeads"].forEach(id=>$("#"+id).addEventListener(id==="leadSearch"?"input":"change",renderLeads));
function addModal(open=true){$("#leadModal").classList.toggle("open",open)}
$("#addLeadTop").onclick=$("#addLead").onclick=()=>addModal(true);$("#closeModal").onclick=$("#cancelModal").onclick=()=>addModal(false);$("#leadModal").onclick=e=>{if(e.target.id==="leadModal")addModal(false)};
$("#leadForm").onsubmit=e=>{e.preventDefault();const f=new FormData(e.target),s=f.get("scale"),l={id:"custom-"+Date.now(),name:f.get("name").trim(),website:f.get("website").trim(),phone:f.get("phone").trim(),scale:s,scaleScore:s==="A"?85:s==="B"?62:42,seo:50,visibility:"نیازمند ممیزی",area:f.get("area").trim(),services:f.get("services").trim(),tech:"هنوز ممیزی نشده است.",issue:"پس از ممیزی خودکار تعیین می‌شود.",target:"خدمت + منطقه",plan:"ممیزی فنی، تحقیق کلمه و ساخت برنامه ۹۰روزه.",source:"",critical:false};leads.push(l);save();renderAll();e.target.reset();addModal(false);toast("لید اضافه شد؛ برای تکمیل امتیاز ممیزی را اجرا کنید.")};
/* Medical clinic discovery */
const CLINIC_SPECIALTIES={
 aesthetic:{fa:"کلینیک زیبایی پوست مو لیزر",en:"aesthetic dermatology clinic",services:"زیبایی، پوست، مو و لیزر"},
 "sexual-health":{fa:"کلینیک پزشکی سلامت جنسی سکسولوژی طب جنسی",en:"sexual health sexology sexual medicine clinic",services:"سلامت جنسی، سکسولوژی و طب جنسی"},
 fertility:{fa:"مرکز ناباروری آی وی اف IVF",en:"fertility IVF clinic",services:"ناباروری و IVF"},
 gynecology:{fa:"کلینیک تخصصی زنان و زایمان",en:"gynecology women health clinic",services:"زنان و زایمان"},
 urology:{fa:"کلینیک اورولوژی سلامت مردان",en:"urology men's health clinic",services:"اورولوژی و سلامت مردان"},
 dental:{fa:"کلینیک دندانپزشکی",en:"dental clinic",services:"دندان‌پزشکی"},
 "mental-health":{fa:"کلینیک روانپزشکی روانشناسی",en:"psychiatry psychology mental health clinic",services:"روان‌پزشکی و روان‌شناسی"},
 physiotherapy:{fa:"کلینیک فیزیوتراپی توانبخشی",en:"physiotherapy rehabilitation clinic",services:"فیزیوتراپی و توان‌بخشی"},
 nutrition:{fa:"کلینیک تغذیه رژیم درمانی",en:"nutrition weight management clinic",services:"تغذیه و کنترل وزن"},
 ophthalmology:{fa:"کلینیک چشم پزشکی",en:"ophthalmology eye clinic",services:"چشم‌پزشکی"},
 ent:{fa:"کلینیک گوش حلق بینی",en:"ENT clinic",services:"گوش، حلق و بینی"},
 general:{fa:"درمانگاه کلینیک پزشکی",en:"medical clinic polyclinic",services:"خدمات عمومی پزشکی"}
};
function selectedClinicEngines(){return $$('#discovery .engine input:checked').map(x=>x.value)}
function buildClinicSearchQuery(){const spec=CLINIC_SPECIALTIES[$("#clinicSpecialty").value]||CLINIC_SPECIALTIES.general,loc=$("#clinicLocation").value.trim()||"تهران",lang=$("#clinicLanguage").value,official=$("#officialOnly").checked;let parts=[];if(lang!=="en")parts.push(spec.fa);if(lang!=="fa")parts.push(spec.en);parts.push(loc);if(official)parts.push("وب سایت رسمی شماره تماس آدرس");if($("#clinicSpecialty").value==="sexual-health")parts.push("پزشک متخصص درمان پزشکی -خدمات بزرگسال -ماساژ");$("#clinicQuery").value=parts.join(" ");return parts.join(" ")}
function clinicSearchLinks(query){const q=encodeURIComponent(query),directory=encodeURIComponent(`site:paziresh24.com OR site:nobat.ir ${query}`);return{duckduckgo:`https://duckduckgo.com/?q=${q}`,google:`https://www.google.com/search?q=${q}`,bing:`https://www.bing.com/search?q=${q}`,brave:`https://search.brave.com/search?q=${q}`,medicalDirectories:`https://www.google.com/search?q=${directory}`}}
function renderClinicSearchLinks(links){const names={duckduckgo:"DuckDuckGo",google:"Google",bing:"Bing",brave:"Brave",medicalDirectories:"دایرکتوری‌های پزشکی"};const selected=new Set(selectedClinicEngines());$("#clinicSearchLinks").innerHTML=Object.entries(links||{}).filter(([key])=>key==="medicalDirectories"||selected.has(key)).map(([key,url])=>`<a class="btn sm" href="${safeHref(url)}" target="_blank" rel="noopener">${names[key]||key} ↗</a>`).join("")}
function updateClinicSelectionCount(){if($("#clinicSelectionCount"))$("#clinicSelectionCount").textContent=`${fa(selectedClinicResults.size)} انتخاب`}
function renderClinicResults(){const grid=$("#clinicResultGrid");if(!discoveredClinics.length){grid.innerHTML='<div class="empty" style="grid-column:1/-1">در حالت بدون API، لینک موتورهای جست‌وجو ساخته می‌شود. نتایج API یا کاندیدهای افزوده‌شده اینجا نمایش داده خواهند شد.</div>';updateClinicSelectionCount();return}grid.innerHTML=discoveredClinics.map((c,i)=>`<article class="clinic-result selectable"><input class="clinic-select" type="checkbox" data-select-clinic="${i}" ${selectedClinicResults.has(i)?"checked":""}><span class="pill ${c.verified?"p3":"p2"} verified">${c.verified?"تأییدشده":"کاندید"}</span><h4>${esc(c.aiAnalysis?.normalizedName||c.name||"کلینیک بدون نام")}</h4><div class="specialty-tags"><span class="specialty-tag">${esc(c.specialty||CLINIC_SPECIALTIES[$("#clinicSpecialty").value].services)}</span><span class="specialty-tag">${esc($("#clinicLocation").value)}</span><span class="result-type ${esc(c.aiAnalysis?.resultType||c.resultType||"web-result")}">${esc(c.aiAnalysis?.resultType||c.resultType||"web-result")}</span>${c.aiAnalysis?`<span class="specialty-tag">AI ${fa(c.aiAnalysis.confidence||0)}%</span><span class="specialty-tag">${esc(c.aiAnalysis.priority||"")}</span>`:""}</div><p>${esc(c.address||c.summary||"برای تأیید نیازمند بررسی منبع عمومی است.")}</p>${c.phone?`<p dir="ltr" style="text-align:right">☎ ${esc(c.phone)}</p>`:""}${c.email?`<p dir="ltr" style="text-align:right">✉ ${esc(c.email)}</p>`:""}${c.whatsapp?`<p dir="ltr" style="text-align:right;color:#78e1d8">WhatsApp: ${esc(c.whatsapp)}</p>`:""}${Array.isArray(c.tags)&&c.tags.length?`<div class="specialty-tags">${c.tags.slice(0,6).map(tag=>`<span class="specialty-tag">#${esc(tag)}</span>`).join("")}</div>`:""}${c.contactError?`<div class="recommended-action">${esc(c.contactError)}</div>`:""}${c.aiAnalysis?.reason?`<div class="recommended-action"><b>AI:</b> ${esc(c.aiAnalysis.reason)}<br>${esc(c.aiAnalysis.recommendedNextStep||"")}</div>`:c.recommendedAction?`<div class="recommended-action">${esc(c.recommendedAction)}</div>`:""}<div class="clinic-result-actions">${c.website?`<a class="btn sm" href="${safeHref(c.website)}" target="_blank" rel="noopener">وب‌سایت</a>`:""}<button class="btn sm" data-add-clinic="${i}">افزودن به لیدها</button>${c.source?`<a class="btn sm" href="${safeHref(c.source)}" target="_blank" rel="noopener">منبع</a>`:""}</div></article>`).join("");updateClinicSelectionCount()}
function showClinicSearchNotice(text,configured=false){const box=$("#clinicSearchNotice");box.textContent=text;box.classList.add("show");box.classList.toggle("configured",configured)}
async function searchMedicalClinics(){
  const query=$("#clinicQuery").value.trim()||buildClinicSearchQuery(),location=$("#clinicLocation").value.trim(),specialty=$("#clinicSpecialty").value,engines=selectedClinicEngines(),links=clinicSearchLinks(query);
  renderClinicSearchLinks(links);$("#searchClinics").disabled=true;$("#clinicSearchSummary").textContent=uiLanguage==="en"?"Preparing search…":"در حال آماده‌سازی جست‌وجو…";
  try{
    if(apiLive){
      const r=await fetch("/api/clinic-search",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({query,location,specialty,engines})}),j=await r.json();
      if(!j.ok)throw new Error(j.error||"Clinic search failed");
      if(j.searchLinks)renderClinicSearchLinks(j.searchLinks);
      discoveredClinics=Array.isArray(j.items)?j.items:[];selectedClinicResults.clear();
      if(j.configured){
        $("#clinicSearchSummary").textContent=uiLanguage==="en"?`${discoveredClinics.length} candidates received from ${j.provider||"search API"}`:`${fa(discoveredClinics.length)} کاندید از ${j.provider||"Search API"} دریافت شد`;
        showClinicSearchNotice(uiLanguage==="en"?"Automatic API mode is active. Results remain unverified until reviewed.":"حالت جست‌وجوی خودکار فعال است؛ نتایج تا زمان بررسی، کاندید تأییدنشده هستند.",true);
      }else{
        $("#clinicSearchSummary").textContent=uiLanguage==="en"?`${engines.length} search links are ready`:`لینک‌های ${engines.length} موتور جست‌وجو آماده شد`;
        showClinicSearchNotice(uiLanguage==="en"?"Link mode: no approved automatic search adapter is configured. Add GOOGLE_PLACES_API_KEY or BRAVE_SEARCH_API_KEY as a server Secret, or open a link and import saved HTML. Google/Bing/DDG result pages are not scraped automatically.":"حالت لینک: Adapter مجاز جست‌وجوی خودکار تنظیم نشده است. GOOGLE_PLACES_API_KEY یا BRAVE_SEARCH_API_KEY را در Secretهای سرور اضافه کنید؛ یا لینک را باز و HTML ذخیره‌شده را وارد کنید. صفحات نتایج Google/Bing/DDG به‌صورت خودکار Scrape نمی‌شوند.");
      }
    }else{
      $("#clinicSearchSummary").textContent=uiLanguage==="en"?"Offline link mode":"حالت آفلاین؛ لینک‌ها آماده‌اند";
      showClinicSearchNotice(uiLanguage==="en"?"Backend is offline. Search links still work, but automatic result import requires the running server.":"Backend آفلاین است. لینک‌های جست‌وجو کار می‌کنند، اما دریافت خودکار نتایج به سرور فعال نیاز دارد.");
    }
    renderClinicResults();
  }catch(e){$("#clinicSearchSummary").textContent=uiLanguage==="en"?"Search failed":"جست‌وجو ناموفق بود";showClinicSearchNotice(e.message);toast(e.message)}finally{$("#searchClinics").disabled=false}
}
function candidateToLead(c,index=0){const spec=CLINIC_SPECIALTIES[$("#clinicSpecialty").value]||CLINIC_SPECIALTIES.general;return{id:`discovered-${Date.now()}-${index}`,name:c.aiAnalysis?.normalizedName||c.name||"کلینیک جدید",scale:"C",scaleScore:40,seo:45,visibility:"کاندید کشف‌شده؛ نیازمند تأیید",website:c.website||"",phone:c.phone||"",email:c.email||"",whatsapp:c.whatsapp||"",tags:Array.isArray(c.tags)?c.tags:[],area:c.address||$("#clinicLocation").value,services:c.aiAnalysis?.specialty||c.specialty||spec.services,tech:"هنوز ممیزی فنی نشده است.",issue:"نیازمند ممیزی سئو، هویت عمومی و مجوز پزشکی.",target:`${spec.services} ${$("#clinicLocation").value}`,plan:"تأیید هویت عمومی، ممیزی فنی و طراحی برنامه ۹۰روزه.",source:c.source||"",resultType:c.aiAnalysis?.resultType||c.resultType||"candidate",aiAnalysis:c.aiAnalysis||null,critical:false}}
function addDiscoveredClinic(index){const c=discoveredClinics[index];if(!c)return;const host=auditHost(c.website),existing=leads.find(l=>host&&auditHost(l.website)===host);if(existing){Object.assign(existing,{name:c.name||existing.name,phone:c.phone||existing.phone,email:c.email||existing.email,whatsapp:c.whatsapp||existing.whatsapp,tags:[...new Set([...(existing.tags||[]),...(c.tags||[])])],area:c.address||existing.area,source:c.source||existing.source,visibility:"کاندید کشف‌شده؛ نیازمند تأیید"});toast("این دامنه قبلاً وجود داشت و به‌روزرسانی شد.")}else{leads.push(candidateToLead(c,index));toast("کاندید به بانک لیدها اضافه شد.")}save();renderAll()}
function selectedClinics(){return [...selectedClinicResults].sort((a,b)=>a-b).map(i=>discoveredClinics[i]).filter(Boolean)}
async function enrichSelectedClinics(){const items=selectedClinics();if(!items.length)return toast("حداقل یک نتیجه را انتخاب کنید.");if(!apiLive)return toast("Enrichment به Backend فعال نیاز دارد.");const button=$("#enrichSelectedClinics");button.disabled=true;button.textContent="در حال استخراج نام کلینیک‌ها…";try{const r=await fetch("/api/enrich-clinics",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({items,specialty:CLINIC_SPECIALTIES[$("#clinicSpecialty").value].services})}),j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||"Enrichment failed");discoveredClinics=j.items||[];selectedClinicResults=new Set(discoveredClinics.map((_,i)=>i));$("#clinicSearchSummary").textContent=`${fa(discoveredClinics.length)} نام/موجودیت پزشکی غنی‌سازی شد`;renderClinicResults();toast(j.disclaimer)}catch(e){toast(e.message)}finally{button.disabled=false;button.textContent="تبدیل صفحات به نام کلینیک"}}
async function findSelectedPublicContacts(){const indexes=[...selectedClinicResults].sort((a,b)=>a-b).slice(0,6);if(!indexes.length)return toast("حداقل یک نتیجه را انتخاب کنید.");if(!apiLive)return toast("استخراج تماس عمومی به Backend فعال نیاز دارد.");const button=$("#findSelectedContacts");button.disabled=true;button.textContent="در حال بررسی صفحات تماس…";let updated=0;try{for(const index of indexes){const candidate=discoveredClinics[index];if(!candidate?.website)continue;try{const r=await fetch("/api/contact-enrich",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({url:candidate.website,maxPages:3})}),j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||"Contact enrichment failed");Object.assign(candidate,{website:j.finalUrl||candidate.website,phone:j.primaryPhone||candidate.phone||"",email:j.primaryEmail||candidate.email||"",whatsapp:j.whatsappNumber||candidate.whatsapp||"",whatsappLinks:j.whatsappLinks||[],tags:[...new Set([...(candidate.tags||[]),...(j.tags||[])])],socialLinks:j.socialLinks||candidate.socialLinks||[],address:(j.addresses||[])[0]||candidate.address||"",contactPages:j.pagesChecked||[],contactEnriched:true});updated++}catch(error){candidate.contactError=error.message}}renderClinicResults();toast(`${fa(updated)} نتیجه با تماس‌های عمومی به‌روزرسانی شد. قبل از ارتباط، مالکیت و رضایت را تأیید کنید.`)}finally{button.disabled=false;button.textContent="یافتن تلفن، ایمیل و WhatsApp"}}
async function analyzeSelectedClinicCandidates(){const items=selectedClinics();if(!items.length)return toast("حداقل یک نتیجه را انتخاب کنید.");if(!apiLive)return toast("تحلیل AI به Backend و کلید Gemini نیاز دارد.");const button=$("#analyzeSelectedClinics");button.disabled=true;button.textContent="در حال تحلیل AI…";try{const r=await fetch("/api/analyze-clinic-candidates",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({items,language:uiLanguage})}),j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||"AI candidate analysis failed");const selectedIndexes=[...selectedClinicResults].sort((a,b)=>a-b);(j.items||[]).forEach(a=>{const globalIndex=selectedIndexes[a.index];if(discoveredClinics[globalIndex])discoveredClinics[globalIndex].aiAnalysis=a});renderClinicResults();toast(`${fa((j.items||[]).length)} نتیجه با AI تحلیل شد.`)}catch(e){toast(e.message)}finally{button.disabled=false;button.textContent="تحلیل AI منتخب"}}
