function addSelectedClinicsToLeads(){const selected=[...selectedClinicResults].sort((a,b)=>a-b);if(!selected.length)return toast("حداقل یک نتیجه را انتخاب کنید.");let added=0,updated=0;selected.forEach(index=>{const c=discoveredClinics[index],host=auditHost(c?.website),existing=leads.find(l=>host&&auditHost(l.website)===host);if(existing){Object.assign(existing,{name:c.name||existing.name,phone:c.phone||existing.phone,email:c.email||existing.email,whatsapp:c.whatsapp||existing.whatsapp,tags:[...new Set([...(existing.tags||[]),...(c.tags||[])])],area:c.address||existing.area,source:c.source||existing.source});updated++}else if(c){leads.push(candidateToLead(c,index));added++}});save();renderAll();toast(`${fa(added)} لید افزوده و ${fa(updated)} لید به‌روزرسانی شد.`)}
