function renderArticleReport(report,lang){const en=lang==="en",wordGood=!!report.wordCountPass,primaryGood=report.primaryCount>=report.primaryMin&&report.primaryCount<=report.primaryMax,firstGood=!!report.primaryInFirst100;$("#articleReport").innerHTML=`<div class="report-card ${wordGood?"good":"warn"}"><span>${en?"Words":"تعداد کلمات"}</span><b>${fa(report.wordCount)} / ${fa(report.targetWordCount)}</b></div><div class="report-card ${primaryGood?"good":"warn"}"><span>${en?"Primary repeats":"تکرار کلمه اصلی"}</span><b>${fa(report.primaryCount)} (${fa(report.primaryMin)}–${fa(report.primaryMax)})</b></div><div class="report-card"><span>${en?"Density":"چگالی"}</span><b>${report.density}%</b></div><div class="report-card ${firstGood?"good":"warn"}"><span>${en?"First 100 words":"۱۰۰ کلمه اول"}</span><b>${firstGood?"✓":"!"}</b></div>${report.secondary?.length?`<div class="secondary-report"><b>${en?"Secondary keywords":"کلمات فرعی"}</b><div class="secondary-list">${report.secondary.map(x=>`<span class="secondary-item">${esc(x.keyword)}: ${fa(x.count)}</span>`).join("")}</div></div>`:""}`}
async function generateArticle(){const language=$("#articleLanguage").value,payload={language,title:$("#articleTitle").value.trim(),outline:$("#articleOutline").value.trim(),primaryKeyword:$("#articlePrimaryKeyword").value.trim(),secondaryKeywords:$("#articleSecondaryKeywords").value.trim(),targetWordCount:+$("#articleWordCount").value||900,isRewrite:$("#articleRewrite").checked,rewriteNotes:$("#articleRewriteNotes").value.trim()};const en=language==="en";if(!payload.title||!payload.outline||!payload.primaryKeyword)return toast(en?"Title, outline and primary keyword are required.":"عنوان، Outline و کلمه اصلی الزامی است.");if(!apiLive)return toast(en?"A running backend and Gemini key are required.":"برای تولید، Backend فعال و کلید Gemini لازم است.");const button=$("#generateArticle");button.disabled=true;button.classList.add("generating");button.textContent=en?"Generating…":"در حال تولید…";$("#articleStatus").textContent=en?"Gemini is writing and validating the article…":"Gemini در حال نگارش و کنترل مقاله است…";try{const r=await fetch("/api/generate-article",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}),j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||"Generation failed");$("#articleOutput").value=j.article;renderArticleReport(j.report,j.language);$("#articleStatus").textContent=(en?`Model: ${j.model} · API key ${j.keyNumber}`:`مدل: ${j.model} · کلید API شماره ${j.keyNumber}`)+(j.autoCorrected?(en?" · Auto-corrected":" · اصلاح خودکار شد"):"");toast(en?"Article generated. Review it before publishing.":"مقاله تولید شد؛ قبل از انتشار بازبینی کنید.")}catch(e){$("#articleStatus").textContent=en?"Generation failed":"تولید ناموفق بود";toast(e.message)}finally{button.disabled=false;button.classList.remove("generating");button.textContent=en?"Generate article with Gemini":"تولید مقاله با Gemini"}}
$("#articleLanguage").onchange=applyArticleLanguage;$("#articleRewrite").onchange=e=>{$("#rewriteNotesWrap").style.display=e.target.checked?"block":"none"};$("#generateArticle").onclick=generateArticle;$("#copyArticle").onclick=()=>{const text=$("#articleOutput").value;if(text)copyText(text)};$("#downloadArticle").onclick=()=>{const text=$("#articleOutput").value;if(text)download(`seo-article-${Date.now()}.md`,text,"text/markdown")};$("#clearArticle").onclick=()=>{$("#articleOutput").value="";$("#articleReport").innerHTML='<div class="empty">—</div>';$("#articleStatus").textContent=$("#articleLanguage").value==="en"?"Cleared":"پاک شد"};applyArticleLanguage();
function normalizeIntegrationStatus(payload){const base={sendEnabled:false,dryRun:true,providers:{whatsapp:false,telegram:false,bale:false,rubika:false,soroush:false,eitaa:false,email:false,sms:false,divar:false},vendorSearchConfigured:false,clinicSearchConfigured:false,proposalPdfMode:"browser-print",webApps:{bale:"https://web.bale.ai",rubika:"https://web.rubika.ir",soroush:"https://web.splus.ir",eitaa:"https://web.eitaa.com",divar:"https://divar.ir/"},notes:{}};const p=payload&&typeof payload==="object"?payload:{};if(p.providers&&typeof p.providers==="object")Object.keys(base.providers).forEach(k=>base.providers[k]=!!p.providers[k]);if(Array.isArray(p.integrations))p.integrations.forEach(x=>{const key=x?.channel==="divar-chat"?"divar":x?.channel;if(key in base.providers)base.providers[key]=!!x.ok});return{...base,...p,dryRun:p.dryRun??p.dryRunDefault??true,sendEnabled:!!p.sendEnabled,providers:base.providers,webApps:{...base.webApps,...(p.webApps||{})},notes:{...base.notes,...(p.notes||{})}}}
