function offlineAudit(url){const host=(url.match(/https?:\/\/([^/]+)/i)||[])[1]?.replace(/^www\./,"");const l=leads.find(x=>x.website&&x.website.includes(host));if(!l)return{ok:false,error:"API زنده فعال نیست و نتیجه ذخیره‌شده‌ای برای این دامنه وجود ندارد."};return{ok:true,offline:true,status:l.critical?l.id==="blue"?502:l.id==="elize"?404:301:200,finalUrl:l.website,seoScore:l.seo,title:l.name,issues:[l.issue],wins:[l.tech],schemaTypes:[],internalLinks:"—",robots:"—",sitemap:"—"}}
