function renderQueue(){const done=queue.filter(x=>x.state==="done").length;$("#queueSummary").textContent=queue.length?`${fa(done)} از ${fa(queue.length)} تکمیل شده`:"آماده برای اجرا";if(!queue.length){$("#auditQueue").innerHTML='<div class="empty">دامنه‌ها را وارد و «شروع ممیزی» را انتخاب کنید.</div>';return}$("#auditQueue").innerHTML=queue.map((q,i)=>{const r=q.result||{};if(q.state==="running")return`<div class="audit-card"><div class="audit-url">${esc(q.url)}</div><p><span class="spinner"></span> در حال دریافت، استخراج لینک‌ها و تحلیل فنی…</p></div>`;if(q.state==="error")return`<div class="audit-card"><div class="audit-card-head"><div><div class="audit-url">${esc(q.url)}</div><p class="muted">${esc(r.error||"خطای نامشخص")}</p></div><span class="status error">خطا</span></div><div class="audit-actions"><button class="btn sm" data-audit-rerun="${i}">تلاش مجدد</button><a class="btn sm" href="${safeHref(q.url)}" target="_blank" rel="noopener">بازکردن سایت</a></div></div>`;const host=(()=>{try{return new URL(r.finalUrl||q.url).hostname}catch(_){return""}})(),siteQuery=encodeURIComponent(`site:${host}`),google=`https://www.google.com/search?q=${siteQuery}`,ddg=`https://duckduckgo.com/?q=${siteQuery}`;return`<article class="audit-card"><div class="audit-card-head"><div><a class="audit-url" href="${safeHref(r.finalUrl||q.url)}" target="_blank" rel="noopener">${esc(r.finalUrl||q.url)}</a><div class="audit-title"><b>HTTP ${esc(r.status)} · ${r.offline?"نتیجه ذخیره‌شده":"ممیزی زنده"}</b>${r.title?` · ${esc(r.title)}`:""}</div></div><div class="audit-score-large">${fa(r.seoScore??0)}</div></div><div class="audit-metrics"><div class="audit-metric"><span>H1</span><b>${esc(r.h1Count??"—")}</b></div><div class="audit-metric"><span>Schema</span><b>${fa((r.schemaTypes||[]).length)}</b></div><div class="audit-metric"><span>Internal</span><b>${fa(r.internalLinks??0)}</b></div><div class="audit-metric"><span>External</span><b>${fa(r.externalLinks??0)}</b></div><div class="audit-metric"><span>Robots</span><b>${r.robots===true?"✓":r.robots===false?"✕":"—"}</b></div><div class="audit-metric"><span>Sitemap</span><b>${r.sitemap===true?"✓":r.sitemap===false?"✕":"—"}</b></div></div><div class="audit-notes"><div class="audit-note"><b>مشکلات اندازه‌گیری‌شده</b>${auditBulletList(r.issues)}</div><div class="audit-note"><b>موارد موفق</b>${auditBulletList(r.wins)}</div></div>${auditLinks("لینک‌های داخلی نمونه",r.internalLinkSamples)}${auditLinks("لینک‌های خارجی نمونه",r.externalLinkSamples)}${auditLinks("شبکه‌های اجتماعی",r.socialLinks)}<div class="audit-contacts">${(r.phoneLinks||[]).map(x=>`<span class="audit-contact">☎ ${esc(x)}</span>`).join("")}${(r.emailLinks||[]).map(x=>`<span class="audit-contact">✉ ${esc(x)}</span>`).join("")}${r.whatsappNumber?`<span class="audit-contact">WhatsApp ${esc(r.whatsappNumber)}</span>`:""}</div>${Array.isArray(r.tags)&&r.tags.length?`<div class="specialty-tags">${r.tags.slice(0,10).map(x=>`<span class="specialty-tag">#${esc(x)}</span>`).join("")}</div>`:""}<div class="audit-actions"><a class="btn sm" href="${safeHref(r.finalUrl||q.url)}" target="_blank" rel="noopener">بازکردن سایت</a><button class="btn sm primary" data-audit-ai="${i}">تحلیل AI همین ممیزی</button><button class="btn sm" data-audit-lead="${i}">افزودن/به‌روزرسانی لید</button><button class="btn sm blue" data-audit-db="${i}">ذخیره Audit و پیشنهاد در دیتابیس</button><button class="btn sm" data-audit-copy="${i}">کپی JSON</button><button class="btn sm" data-audit-export="${i}">دانلود JSON</button><button class="btn sm" data-audit-rerun="${i}">اجرای مجدد</button><a class="btn sm" href="${google}" target="_blank" rel="noopener">Google site:</a><a class="btn sm" href="${ddg}" target="_blank" rel="noopener">DuckDuckGo site:</a></div></article>`}).join("")}
function auditHost(url){try{return new URL(url).hostname.replace(/^www\./,"")}catch(_){return""}}
function mergeAuditUrls(urls){const current=$("#auditUrls").value.split(/\n|,/).map(x=>x.trim()).filter(Boolean),all=[...current,...urls].filter(Boolean),seen=new Set(),clean=[];for(let url of all){if(!/^https?:\/\//i.test(url))url="https://"+url;const key=auditHost(url)||url;if(!seen.has(key)){seen.add(key);clean.push(url)}}$("#auditUrls").value=clean.join("\n");toast(`${fa(clean.length)} URL آماده ممیزی است.`)}
function addOrUpdateLeadFromAudit(result){const url=result.finalUrl||result.requestedUrl||"",host=auditHost(url);let lead=leads.find(l=>auditHost(l.website)===host&&host);const phone=(result.phoneLinks||[])[0]||"";if(lead){lead.website=url;lead.seo=result.seoScore??lead.seo;lead.tech=(result.issues||[]).slice(0,3).join("؛ ")||"ممیزی فنی تکمیل شد.";if(phone&&!lead.phone)lead.phone=phone;if((result.emailLinks||[])[0]&&!lead.email)lead.email=result.emailLinks[0];if(result.whatsappNumber&&!lead.whatsapp)lead.whatsapp=result.whatsappNumber;lead.tags=[...new Set([...(lead.tags||[]),...(result.tags||[])])];lead.visibility="ممیزی زنده انجام شد";toast("پرونده لید با نتیجه ممیزی به‌روزرسانی شد.")}else{lead={id:"audit-"+Date.now(),name:result.title||host||"کلینیک جدید",scale:"C",scaleScore:40,seo:result.seoScore??50,visibility:"کاندید حاصل از ممیزی",website:url,phone,email:(result.emailLinks||[])[0]||"",whatsapp:result.whatsappNumber||"",tags:result.tags||[],area:"نیازمند تأیید",services:"کلینیک پزشکی — نیازمند طبقه‌بندی",tech:(result.issues||[]).slice(0,3).join("؛ ")||"ممیزی فنی تکمیل شد.",issue:(result.issues||[])[0]||"نیازمند تحلیل",target:"خدمت + منطقه",plan:"تأیید هویت، تحلیل AI و برنامه ۹۰روزه.",source:url,critical:(result.status??200)>=500};leads.push(lead);toast("نتیجه ممیزی به‌عنوان لید جدید اضافه شد.")}save();renderAll();return lead}
async function saveAuditOpportunityToDatabase(result){const lead=addOrUpdateLeadFromAudit(result),score=Number(result.seoScore||lead.seo||0),opportunityScore=opportunityFromAudit(score,!lead.website),recommendedPackage=packageFromAudit(score,!lead.website),row={...lead,seoScore:score,opportunityScore,recommendedPackage,status:"audited",resultType:"audited-opportunity",audit:result};const j=await persistLeadItems([row]);toast(`${fa(j.saved||1)} فرصت ممیزی‌شده با پیشنهاد ${recommendedPackage} در دیتابیس ذخیره شد.`);return j}
async function rerunAuditIndex(index){const q=queue[index];if(!q)return;q.state="running";q.result=null;renderQueue();const result=await oneAudit(q.url);q.result=result;q.state=result.ok?"done":"error";renderQueue()}
$("#auditQueue").onclick=async e=>{const button=e.target.closest("[data-audit-ai],[data-audit-lead],[data-audit-db],[data-audit-copy],[data-audit-export],[data-audit-rerun]");if(!button)return;const attr=["auditAi","auditLead","auditDb","auditCopy","auditExport","auditRerun"].find(k=>button.dataset[k]!==undefined),index=+(button.dataset[attr]),q=queue[index];if(!q)return;if(attr==="auditAi"){selectedAuditForAi=q.result;$("#aiSeoUrl").value=q.result.finalUrl||q.url;const host=auditHost(q.url),lead=leads.find(l=>auditHost(l.website)===host);if(lead)$("#aiSeoLead").value=lead.id;$("#aiSeoResult").innerHTML='<div class="empty">ممیزی اندازه‌گیری‌شده انتخاب شد؛ «تحلیل Gemini» را اجرا کنید.</div>';$("#aiSeoResult").scrollIntoView({behavior:"smooth",block:"start"})}else if(attr==="auditLead")addOrUpdateLeadFromAudit(q.result);else if(attr==="auditDb"){button.disabled=true;try{await saveAuditOpportunityToDatabase(q.result)}catch(error){toast(error.message)}finally{button.disabled=false}}else if(attr==="auditCopy")copyText(JSON.stringify(q.result,null,2));else if(attr==="auditExport")download(`audit-${auditHost(q.url)||index}.json`,JSON.stringify(q.result,null,2),"application/json");else if(attr==="auditRerun")await rerunAuditIndex(index)};
$("#loadLeadUrls").onclick=()=>mergeAuditUrls(leads.map(l=>l.website).filter(Boolean));$("#loadDiscoveredUrls").onclick=()=>mergeAuditUrls(discoveredClinics.map(c=>c.website).filter(Boolean));$("#normalizeAuditUrls").onclick=()=>mergeAuditUrls([]);$("#clearAuditUrls").onclick=()=>{$("#auditUrls").value=""};
async function runAudits(){const urls=$("#auditUrls").value.split(/\n|,/).map(x=>x.trim()).filter(Boolean).slice(0,8);if(!urls.length)return toast("حداقل یک دامنه وارد کنید.");queue=urls.map(url=>({url,state:"waiting",result:null}));renderQueue();for(const q of queue){q.state="running";renderQueue();const r=await oneAudit(q.url);q.result=r;q.state=r.ok?"done":"error";if(r.ok){const host=(q.url.match(/(?:https?:\/\/)?([^/]+)/)||[])[1]?.replace(/^www\./,"");const l=leads.find(x=>x.website&&x.website.includes(host));if(l&&apiLive){l.seo=r.seoScore;l.tech=`HTTP ${r.status}؛ ${r.issues?.[0]||r.wins?.[0]||"ممیزی تکمیل شد"}`;l.critical=r.status>=500||r.status===0;}}renderQueue();save()}renderAll();toast("صف ممیزی تکمیل شد.")}
