function renderAiSeoReview(result){const a=result.aiAnalysis||{},m=result.measuredAudit||{},lang=result.language||"fa",en=lang==="en";const issues=Array.isArray(a.issues)?a.issues:[],road=a.roadmap||{},pkg=a.package||{},out=a.outreach||{},gaps=Array.isArray(a.contentGaps)?a.contentGaps:[];$("#aiSeoResult").innerHTML=`<div class="ai-summary"><h3>${en?"AI SEO Review":"تحلیل AI سئو"}</h3><p>${esc(a.executiveSummary||"—")}</p></div><div class="ai-score-row"><div class="ai-score"><span>${en?"Measured audit":"امتیاز ممیزی قطعی"}</span><b>${fa(m.seoScore??0)}/100</b></div><div class="ai-score"><span>${en?"AI advisory score":"امتیاز مشورتی AI"}</span><b>${fa(a.aiSeoScore??0)}/100</b></div><div class="ai-score"><span>${en?"Lead opportunity":"فرصت لید"}</span><b>${fa(a.opportunityScore??0)}/100</b></div></div><div class="ai-section"><h4>${en?"Measured facts":"داده‌های اندازه‌گیری‌شده"}</h4><div class="ai-facts">${(a.measuredFacts||[]).map(x=>`<span class="ai-fact">${esc(x)}</span>`).join("")||"—"}</div></div><div class="ai-section"><h4>${en?"Prioritized issues":"مشکلات اولویت‌بندی‌شده"}</h4>${issues.map(i=>`<div class="ai-issue"><div class="ai-issue-head"><h5>${esc(i.title||"Issue")}</h5><span class="severity severity-${esc(i.severity||"low")}">${esc(i.severity||"low")}</span></div><p><b>${en?"Evidence":"شاهد"}:</b> ${esc(i.evidence||"—")}</p><p><b>${en?"Impact":"اثر"}:</b> ${esc(i.impact||"—")}</p><p><b>${en?"Fix":"راهکار"}:</b> ${esc(i.fix||"—")} · ${esc(i.effort||"")}</p></div>`).join("")||"—"}</div><div class="ai-section"><h4>${en?"Quick wins":"Quick Wins"}</h4>${listHtml(a.quickWins)}</div><div class="ai-section"><h4>${en?"30/60/90 roadmap":"برنامه ۳۰/۶۰/۹۰"}</h4><div class="roadmap-grid"><div class="roadmap-col"><b>1–30</b>${listHtml(road.days1to30)}</div><div class="roadmap-col"><b>31–60</b>${listHtml(road.days31to60)}</div><div class="roadmap-col"><b>61–90</b>${listHtml(road.days61to90)}</div></div></div><div class="ai-section"><h4>${en?"Recommended package":"پکیج پیشنهادی"}</h4><div class="ai-package"><b>${esc(pkg.name||"—")}</b><p>${esc(pkg.reason||"")}</p><div class="specialty-tags"><span class="specialty-tag">${esc(pkg.setupBudget||"—")}</span><span class="specialty-tag">${esc(pkg.monthlyFee||"—")}</span><span class="specialty-tag">${esc(pkg.mediaBudget||"—")}</span><span class="specialty-tag">${esc(pkg.duration||"—")}</span></div></div></div><div class="ai-section"><h4>${en?"Content gaps":"شکاف محتوایی"}</h4>${gaps.map(g=>`<div class="ai-issue"><h5>${esc(g.cluster||"—")} · ${esc(g.intent||"")}</h5>${listHtml(g.recommendedAssets)}</div>`).join("")||"—"}</div><div class="ai-section"><h4>KPI</h4>${listHtml(a.kpis)}</div><div class="ai-section"><h4>${en?"Outreach drafts":"متن‌های ارتباط"}</h4><div class="ai-outreach"><pre>${esc(out.whatsapp||"—")}</pre><pre>${esc((out.emailSubject||"")+"\n\n"+(out.emailBody||""))}</pre></div><div class="audit-actions"><button class="btn sm" data-ai-copy-wa>کپی WhatsApp</button><button class="btn sm primary" data-ai-use-message>انتقال به پیام‌رسانی</button><button class="btn sm" data-ai-use-package>ساخت پیشنهاد با این پکیج</button><button class="btn sm blue" data-ai-save-db>ذخیره تحلیل و پیشنهاد در دیتابیس</button></div></div>`}
async function runAiSeoReview(){const lead=leads.find(x=>x.id===$("#aiSeoLead").value),url=$("#aiSeoUrl").value.trim()||lead?.website||"",language=$("#aiSeoLanguage").value;if(!url)return toast(language==="en"?"Enter a public URL.":"URL عمومی را وارد کنید.");if(!apiLive)return toast(language==="en"?"A running backend and Gemini key are required.":"Backend فعال و کلید Gemini لازم است.");const button=$("#runAiSeoReview");button.disabled=true;button.textContent=language==="en"?"Auditing and analyzing…":"در حال ممیزی و تحلیل…";$("#aiSeoResult").innerHTML='<div class="empty">Gemini + deterministic audit…</div>';try{const sameAudit=selectedAuditForAi&&auditHost(selectedAuditForAi.finalUrl||selectedAuditForAi.requestedUrl)===auditHost(url),payload={url,language,lead:lead?{name:lead.name,scale:lead.scale,area:lead.area,services:lead.services,opportunity:opportunity(lead)}:{}};if(sameAudit)payload.audit=selectedAuditForAi;const r=await fetch("/api/ai-seo-review",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}),j=await r.json();if(!r.ok||!j.ok)throw new Error(j.error||"AI SEO review failed");aiSeoLastResult=j;renderAiSeoReview(j);toast(j.disclaimer)}catch(e){$("#aiSeoResult").innerHTML=`<div class="empty">${esc(e.message)}</div>`}finally{button.disabled=false;button.textContent=language==="en"?"Audit + Gemini analysis":"ممیزی + تحلیل Gemini"}}
async function saveAiSeoOpportunityToDatabase(){if(!aiSeoLastResult)throw new Error("ابتدا تحلیل AI را اجرا کنید.");const measured=aiSeoLastResult.measuredAudit||{},analysis=aiSeoLastResult.aiAnalysis||{},url=measured.finalUrl||measured.requestedUrl||$("#aiSeoUrl").value.trim(),host=auditHost(url);let lead=leads.find(x=>x.id===$("#aiSeoLead").value)||leads.find(x=>auditHost(x.website)===host&&host);if(!lead)lead=addOrUpdateLeadFromAudit({...measured,finalUrl:url,title:measured.title||host});const score=Number(measured.seoScore??lead.seo??0),opportunityScore=Number(analysis.opportunityScore??opportunityFromAudit(score,!url)),recommendedPackage=analysis.package?.name||packageFromAudit(score,!url),row={...lead,website:url,seoScore:score,opportunityScore,recommendedPackage,status:"ai-reviewed",resultType:"ai-seo-opportunity",audit:measured,aiReview:aiSeoLastResult,aiAnalysis:analysis};const j=await persistLeadItems([row]);toast(`${fa(j.saved||1)} تحلیل AI، Audit و پکیج پیشنهادی در دیتابیس ذخیره شد.`);return j}
$("#aiSeoLead").onchange=e=>{const l=leads.find(x=>x.id===e.target.value);if(l?.website){$("#aiSeoUrl").value=l.website;if(selectedAuditForAi&&auditHost(selectedAuditForAi.finalUrl||selectedAuditForAi.requestedUrl)!==auditHost(l.website))selectedAuditForAi=null}};$("#runAiSeoReview").onclick=runAiSeoReview;$("#copyAiSeoJson").onclick=()=>{if(aiSeoLastResult)copyText(JSON.stringify(aiSeoLastResult,null,2))};$("#aiSeoResult").onclick=async e=>{if(!aiSeoLastResult)return;const analysis=aiSeoLastResult.aiAnalysis||{},outreach=analysis.outreach||{},recommended=analysis.package||{},leadId=$("#aiSeoLead").value;if(e.target.closest("[data-ai-copy-wa]"))copyText(outreach.whatsapp||"");if(e.target.closest("[data-ai-use-message]")){go("outreach");fillOutreach();if(leadId&&leads.some(l=>l.id===leadId))$("#outreachLead").value=leadId;$("#messageBox").textContent=outreach.whatsapp||"";$("#messageChars").textContent=`${fa((outreach.whatsapp||"").length)} نویسه`}if(e.target.closest("[data-ai-use-package]")){go("proposals");fillProposal();if(leadId&&leads.some(l=>l.id===leadId))$("#proposalLead").value=leadId;if(recommended.setupBudget)$("#proposalSetup").value=recommended.setupBudget;if(recommended.monthlyFee)$("#proposalMonthly").value=recommended.monthlyFee;if(recommended.mediaBudget)$("#proposalMedia").value=recommended.mediaBudget;if(recommended.duration)$("#proposalDuration").value=recommended.duration;renderProposal()}const saveButton=e.target.closest("[data-ai-save-db]");if(saveButton){saveButton.disabled=true;try{await saveAiSeoOpportunityToDatabase()}catch(error){toast(error.message)}finally{saveButton.disabled=false}}};
function recommend(){const s=$("#recScale").value,seo=+$("#recSeo").value,b=+$("#recBranches").value,risk=$("#recRisk").value;let name=s==="A"||b>=3?"اقتدار تهران — Enterprise":s==="B"||seo<55?"رشد منطقه‌ای — Growth":"پایه محلی — Local Starter";let extra=risk==="critical"?" + بازیابی اضطراری دامنه/SSL":risk==="slow"?" + Sprint سرعت و پایداری":"";let price=name.includes("Enterprise")?"۸۰–۱۴۰ میلیون تومان در ماه":name.includes("Growth")?"۴۵–۷۰ میلیون تومان در ماه":"۲۵–۴۰ میلیون تومان در ماه";$("#recommendation").classList.add("show");$("#recommendation").innerHTML=`<b>${name}${extra}</b><p class="help" style="margin-bottom:0">${price}. اولویت ۳۰ روز نخست: ${risk==="critical"?"رفع بحران فنی و حفاظت از برند":seo<50?"رفع فنی، Entity/NAP و صفحات پول‌ساز":"CRO، خوشه‌های رقابتی و رهگیری لید"}. بودجه رسانه جداگانه و مستقیم پرداخت شود.</p>`}
$("#recommendBtn").onclick=recommend;$$('[data-pkg]').forEach(b=>b.onclick=()=>{const map={local:["C",42,1,"none"],growth:["B",55,1,"none"],enterprise:["A",75,4,"none"]},v=map[b.dataset.pkg];$("#recScale").value=v[0];$("#recSeo").value=v[1];$("#recBranches").value=v[2];$("#recRisk").value=v[3];recommend();$("#recommendation").scrollIntoView({behavior:"smooth"})});
