function agencyLogoMarkup(a,extra=""){const src=a.logoData||a.logoUrl;return`<div class="agency-logo ${extra}"><span>${esc(a.name.slice(0,3))}</span>${src?`<img src="${esc(src)}" alt="لوگوی ${esc(a.name)}" onerror="this.style.display='none'">`:""}</div>`}
function loadAgencyEditor(id){const a=agencies.find(x=>x.id===id)||activeAgency();editingAgencyId=a.id;$("#agencyName").value=a.name||"";$("#agencyPhone").value=a.phone||"";$("#agencyAddress").value=a.address||"";$("#agencyWebsite").value=a.website||"";$("#agencyEmail").value=a.email||"";$("#agencyWhatsapp").value=a.whatsapp||"";$("#agencyHours").value=a.hours||"";renderAgencyPreview(a)}
function renderAgencyPreview(a){$("#agencyPreview").innerHTML=`${agencyLogoMarkup(a)}<div><h3>${esc(a.name)}</h3><p>☎ ${esc(a.phone||"—")} · 🌐 ${esc(a.website||"—")}</p><p>✉ ${esc(a.email||"—")} · WhatsApp: ${esc(a.whatsapp||"—")}</p><p>📍 ${esc(a.address||"—")}</p><p>⏰ ${esc(a.hours||"—")}</p><p><a href="${safeHref(a.source)}" target="_blank" rel="noopener" style="color:#78e1d8">منبع اطلاعات عمومی</a></p></div>`}
function renderAgencies(){if(!agencies.some(x=>x.id===activeAgencyId))activeAgencyId=agencies[0].id;$("#agencyCards").innerHTML=agencies.map(a=>`<article class="agency-card ${a.id===activeAgencyId?"active":""}" data-agency="${esc(a.id)}">${agencyLogoMarkup(a)}<h4>${esc(a.name)}</h4><p>${esc(a.phone||"بدون تلفن")}</p><p>${esc(a.website||"")}</p></article>`).join("");loadAgencyEditor(editingAgencyId||activeAgencyId);fillProposalAgencyProfiles()}
function fillProposalAgencyProfiles(){const sel=$("#proposalAgencyProfile");if(!sel)return;const old=sel.value;sel.innerHTML=agencies.map(a=>`<option value="${esc(a.id)}">${esc(a.name)}${a.id===activeAgencyId?" — فعال":""}</option>`).join("");sel.value=agencies.some(a=>a.id===old)?old:activeAgencyId}
function resizeLogo(file){return new Promise((resolve,reject)=>{if(file.type==="image/svg+xml"){const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsDataURL(file);return}const r=new FileReader();r.onload=()=>{const img=new Image();img.onload=()=>{const max=420,scale=Math.min(1,max/Math.max(img.width,img.height)),c=document.createElement("canvas");c.width=Math.max(1,Math.round(img.width*scale));c.height=Math.max(1,Math.round(img.height*scale));c.getContext("2d").drawImage(img,0,0,c.width,c.height);resolve(c.toDataURL("image/png",.92))};img.onerror=reject;img.src=r.result};r.onerror=reject;r.readAsDataURL(file)})}
$("#agencyCards").onclick=e=>{const c=e.target.closest("[data-agency]");if(c){editingAgencyId=c.dataset.agency;loadAgencyEditor(editingAgencyId)}};$("#setActiveAgency").onclick=()=>{activeAgencyId=editingAgencyId;currentPdfShareUrl="";$("#pdfLinkBox").classList.remove("show");saveAgencies();renderAgencies();renderProposal();generateMessage();toast("شرکت ارسال‌کننده فعال شد.")};$("#agencyForm").onsubmit=e=>{e.preventDefault();const a=agencies.find(x=>x.id===editingAgencyId);Object.assign(a,{name:$("#agencyName").value.trim(),phone:$("#agencyPhone").value.trim(),address:$("#agencyAddress").value.trim(),website:$("#agencyWebsite").value.trim(),email:$("#agencyEmail").value.trim(),whatsapp:$("#agencyWhatsapp").value.trim(),hours:$("#agencyHours").value.trim()});saveAgencies();renderAgencies();renderProposal();toast("پروفایل شرکت ذخیره شد.")};$("#agencyLogoFile").onchange=async e=>{const file=e.target.files[0];if(!file)return;if(file.size>1500000)return toast("حجم لوگو باید کمتر از ۱.۵ مگابایت باشد.");try{const a=agencies.find(x=>x.id===editingAgencyId);a.logoData=await resizeLogo(file);saveAgencies();renderAgencies();renderProposal();toast("لوگو ذخیره شد.")}catch(_){toast("خواندن لوگو ناموفق بود.")}};$("#removeAgencyLogo").onclick=()=>{const a=agencies.find(x=>x.id===editingAgencyId);a.logoData="";a.logoUrl="";saveAgencies();renderAgencies();renderProposal()};
