const NEED_LABELS={seo:"شرکت SEO", "web-design":"طراحی/توسعه وب",security:"امنیت و Incident Response",hosting:"هاست/DevOps",content:"محتوای پزشکی",branding:"برندینگ و Local SEO"};
function partnerNeeds(l){const t=`${l.tech} ${l.issue} ${l.plan}`.toLowerCase(),out=new Set();if(l.critical||/هک|امنیت|redirect|ریدایرکت|دامنه.*نامرتبط/.test(t)){out.add("security");out.add("hosting");out.add("seo")}if(/ssl|502|5xx|dns|timeout|سرعت|پایداری|سرور|resolve/.test(t)){out.add("hosting");out.add("web-design")}if(/وب‌سایت.*پیدا نشد|سایت.*راه‌اندازی|معماری|طراحی|404/.test(t))out.add("web-design");if(l.seo<65||/seo|سئو|رتبه|محتوا|canonical|schema|h1|cannibal/.test(t)){out.add("seo");out.add("content")}if(/nap|برند|entity|محلی|local/.test(t)){out.add("branding");out.add("seo")}if(!out.size)out.add("seo");return[...out]}
function fillPartner(){const sel=$("#partnerLead"),old=sel.value;sel.innerHTML=[...leads].sort((a,b)=>opportunity(b)-opportunity(a)).map(l=>`<option value="${esc(l.id)}">${esc(l.name)} — ${priority(l)}</option>`).join("");if(old&&leads.some(x=>x.id===old))sel.value=old;updatePartnerNeed()}
function updatePartnerNeed(){const l=leads.find(x=>x.id===$("#partnerLead").value);if(!l)return;const needs=partnerNeeds(l),location=$("#partnerLocation").value||"تهران";$("#partnerNeeds").innerHTML=needs.map(x=>`<span class="need-pill">${NEED_LABELS[x]}</span>`).join("");$("#partnerQuery").textContent=`${needs.map(x=>NEED_LABELS[x]).join(" + ")} برای حل «${l.issue}» در ${location}`;renderPartners()}
function vendorMatch(v,l){const needs=partnerNeeds(l),overlap=(v.categories||[]).filter(x=>needs.includes(x)).length;let score=overlap?45+overlap*20:15;if((v.location||"").includes($("#partnerLocation").value))score+=10;if(v.evidence)score+=5;if(v.verified)score+=10;return Math.min(100,score)}
function renderPartners(){const l=leads.find(x=>x.id===$("#partnerLead").value);if(!l)return;const cat=$("#vendorCategory").value,all=[...partnerSearchItems,...vendors],seen=new Set(),list=all.filter(v=>{if(seen.has(v.website||v.name))return false;seen.add(v.website||v.name);return !cat||(cat==="seo-ranked"?v.rankGroup==="seo-tehran-2026":(v.categories||[]).includes(cat))}).sort((a,b)=>vendorMatch(b,l)-vendorMatch(a,l)||(b.prequalificationScore||0)-(a.prequalificationScore||0));$("#partnerSummary").textContent=`${fa(list.length)} کاندید؛ نیاز اصلی: ${partnerNeeds(l).map(x=>NEED_LABELS[x]).join("، ")}`;$("#vendorGrid").innerHTML=list.length?list.map(v=>`<article class="vendor-card"><span class="vendor-score" title="Match score for selected lead">${fa(vendorMatch(v,l))}%</span><div class="vendor-brand"><div class="vendor-logo"><span>${esc(v.name.slice(0,3))}</span>${v.logoUrl?`<img src="${safeHref(v.logoUrl)}" alt="${esc(v.name)}" onerror="this.style.display='none'">`:""}</div><div><h4>${esc(v.name)}</h4>${v.researchRank?`<span class="vendor-rank">رتبه داخلی ${fa(v.researchRank)} · امتیاز ${fa(v.prequalificationScore||0)}</span>`:`<span class="vendor-rank">امتیاز مقدماتی ${fa(v.prequalificationScore||vendorMatch(v,l))}</span>`}</div></div><div class="vendor-meta">${(v.categories||[]).map(c=>`<span class="tag">${esc(NEED_LABELS[c]||c)}</span>`).join("")}<span class="tag">${esc(v.location||"—")}</span><span class="tag">${v.verified?"تأییدشده":"کاندید/تأییدنشده"}</span></div><p>${esc(v.summary||"برای بررسی اولیه به رجیستری افزوده شده است.")}</p>${v.phone?`<p dir="ltr" style="text-align:right">${esc(v.phone)}</p>`:""}${v.scoreBasis?`<div class="vendor-score-breakdown"><b>مبنای امتیاز داخلی:</b> ${esc(v.scoreBasis)}</div>`:""}<a class="evidence" href="${safeHref(v.evidence||v.website)}" target="_blank" rel="noopener">منبع شواهد</a><div style="display:flex;gap:6px;margin-top:10px;flex-wrap:wrap"><a class="btn sm" href="${safeHref(v.website)}" target="_blank" rel="noopener">وب‌سایت</a><button class="btn sm" data-vendor-copy="${esc(v.phone||v.website)}">کپی تماس</button><button class="btn sm" data-vendor-add-agency="${esc(v.id)}">استفاده به‌عنوان پروفایل پیشنهادی</button></div></article>`).join(""):'<div class="empty" style="grid-column:1/-1">مجری منطبق پیدا نشد. جست‌وجوی عمومی یا افزودن دستی را استفاده کنید.</div>'}
