async function findPartners(){const l=leads.find(x=>x.id===$("#partnerLead").value),query=$("#partnerQuery").textContent,location=$("#partnerLocation").value,needs=partnerNeeds(l);$("#findPartners").disabled=true;let links=publicSearchLinks(query);try{if(apiLive){const r=await fetch("/api/vendor-search",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({query,location,categories:needs})}),j=await r.json();if(!j.ok)throw new Error(j.error||"خطای جست‌وجو");if(j.searchLinks)links=j.searchLinks;if(Array.isArray(j.items)){partnerSearchItems=j.items.map((x,i)=>({...x,id:"search-"+Date.now()+i,categories:x.category?[x.category]:needs.slice(0,1),verified:!!x.verified}));renderPartners()}toast(j.configured?`${fa(partnerSearchItems.length)} کاندید از Adapter دریافت شد.`:"Adapter تنظیم نیست؛ لینک‌های جست‌وجوی عمومی ساخته شد.")}else toast("حالت آفلاین: لینک‌های جست‌وجوی عمومی ساخته شد.")}catch(e){toast(e.message)}finally{$("#findPartners").disabled=false;$("#partnerSearchLinks").innerHTML=`<a class="btn sm" href="${esc(links.google)}" target="_blank" rel="noopener">Google Search</a><a class="btn sm" href="${esc(links.linkedin)}" target="_blank" rel="noopener">LinkedIn Companies</a>`}}
$("#partnerLead").onchange=updatePartnerNeed;$("#partnerLocation").oninput=updatePartnerNeed;$("#vendorCategory").onchange=renderPartners;$("#findPartners").onclick=findPartners;$("#vendorForm").onsubmit=e=>{e.preventDefault();const f=new FormData(e.target),v={id:"vendor-"+Date.now(),name:f.get("name").trim(),categories:[f.get("category")],website:f.get("website").trim(),phone:f.get("phone").trim(),location:f.get("location").trim(),summary:"کاندید افزوده‌شده توسط اپراتور؛ نیازمند راستی‌آزمایی مستقل.",evidence:f.get("evidence").trim()||f.get("website").trim(),verified:false,reviewedAt:new Date().toISOString().slice(0,10)};vendors.push(v);saveVendors();e.target.reset();e.target.elements.location.value="تهران";renderPartners();toast("مجری به‌عنوان کاندید تأییدنشده ذخیره شد.")};document.addEventListener("click",e=>{const copy=e.target.closest("[data-vendor-copy]");if(copy)copyText(copy.dataset.vendorCopy);const add=e.target.closest("[data-vendor-add-agency]");if(add){const vendor=vendors.find(v=>v.id===add.dataset.vendorAddAgency)||partnerSearchItems.find(v=>v.id===add.dataset.vendorAddAgency);if(!vendor)return;const id="agency-"+vendor.id.replace(/^v-/,"");let agency=agencies.find(a=>a.id===id);const profile={id,name:vendor.name,address:vendor.location||"",phone:vendor.phone||"",website:vendor.website||"",email:"",whatsapp:"",hours:"نیازمند تأیید",logoUrl:vendor.logoUrl||"",logoData:"",source:vendor.evidence||vendor.website,authorized:false,note:"پروفایل از رجیستری کاندیدها ساخته شده است؛ استفاده از نام و لوگو نیازمند مجوز کتبی شرکت است."};if(agency)Object.assign(agency,profile);else agencies.push(profile);saveAgencies();renderAgencies();toast("پروفایل پیشنهادی ساخته شد؛ قبل از استفاده، مجوز نمایندگی و لوگو را تأیید کنید.")}});
