function selectChannel(channel){selectedChannel=channel;$$('.channel-card').forEach(x=>x.classList.toggle('active',x.dataset.channel===channel));const labels={whatsapp:"شماره WhatsApp با کد کشور",telegram:"Telegram chat_id یا @channel",bale:"Bale chat_id",rubika:"Rubika chat_id",soroush:"شناسه کاربر/کانال سروش پلاس",eitaa:"Eitaa chat_id",email:"نشانی ایمیل",sms:"شماره موبایل با کد کشور",divar:"شناسه گفت‌وگو/اپ کنار دیوار"};const placeholders={whatsapp:"98912…",telegram:"123456789 یا @channel",bale:"chat_id",rubika:"chat_id",soroush:"recipient_id",eitaa:"chat_id",email:"manager@clinic.ir",sms:"98912…",divar:"conversation_id"};const helps={whatsapp:"WhatsApp فقط از Cloud API رسمی استفاده می‌کند؛ قوانین Opt-in و Template/24-hour window باید رعایت شود.",telegram:"Bot تنها پس از Start توسط کاربر یا با دسترسی مجاز گروه/کانال می‌تواند پیام بفرستد.",bale:"ارسال API از tapi.bale.ai انجام می‌شود؛ مخاطب باید بازو را شروع یا گفت‌وگو را مجاز کرده باشد.",rubika:"ارسال متن از Bot API رسمی نسخه ۳ روبیکا انجام می‌شود؛ برای فایل از جریان آپلود رسمی یا انتقال دستی استفاده کنید.",soroush:"ارسال خودکار فقط از وب‌هوک شریک/سازمانی مجاز؛ نسخه وب برای انتقال دستی قابل بازشدن است.",eitaa:"ارسال API از برنامه مجاز ایتا و chat_id انجام می‌شود؛ نسخه وب نیز برای انتقال دستی در دسترس است.",email:"ایمیل از SMTP سرور ارسال می‌شود؛ آدرس فرستنده و امکان Unsubscribe باید معتبر باشد.",sms:"ارسال از وب‌هوک ارائه‌دهنده مجاز انجام می‌شود؛ رضایت و فهرست عدم تماس الزامی است.",divar:"اتوماسیون اسکرپ/مرورگر انجام نمی‌شود. ارسال خودکار فقط با وب‌هوک شریک رسمی دیوار؛ در غیر این صورت انتقال دستی."};$("#recipientLabel").textContent=labels[channel];$("#recipient").placeholder=placeholders[channel];$("#channelHelp").textContent=helps[channel];$("#subjectWrap").style.display=channel==="email"?"block":"none";$("#manualHandoff").style.display=channel==="divar"&&!integrations.providers.divar?"inline-flex":"none";$("#openWhatsAppMobile").style.display=channel==="whatsapp"?"inline-flex":"none";$("#openWhatsAppDesktop").style.display=channel==="whatsapp"?"inline-flex":"none";$("#openChannelWeb").style.display=["bale","rubika","soroush","eitaa","divar"].includes(channel)?"inline-flex":"none";$("#downloadPdfForWhatsApp").style.display=["whatsapp","telegram","bale","rubika","soroush","eitaa","email"].includes(channel)?"inline-flex":"none";updateRecipient();generateMessage()}
function messageFor(l,channel,tone){const finding=l.tech.replace(/\.$/,"");const ask="اگر مایل باشید، گزارش اولیه کوتاه را رایگان ارسال می‌کنم. در صورت عدم تمایل، پیام دیگری ارسال نمی‌شود.";if(tone==="urgent"||l.critical)return `سلام وقت بخیر. این پیام صرفاً یک هشدار فنی درباره ${l.name} است.\n\nدر بررسی عمومی امروز، ${finding}. این موضوع می‌تواند روی اعتماد کاربران، تماس‌ها و حضور جست‌وجویی اثر بگذارد.\n\nپیشنهاد فوری: ${l.plan}\n\nلاگ و زمان بررسی موجود است. اگر مسئول فنی مایل باشد، چک‌لیست اولیه را بدون هزینه ارسال می‌کنیم.`;if(["bale","rubika","soroush","eitaa"].includes(channel))return `سلام وقت بخیر. در بررسی عمومی حضور دیجیتال ${l.name}، ${finding}.\n\nپیشنهاد اجرایی: ${l.plan}\n\n${ask}`;if(channel==="email")return `سلام وقت بخیر،\n\nدر بررسی عمومی حضور دیجیتال ${l.name}، ${finding}.\n\nپیشنهاد ۹۰روزه ما: ${l.plan}\nپکیج متناسب اولیه: ${pkg(l)}.\n\n${ask}\n\nبا احترام\n[نام و اطلاعات تماس]`;if(channel==="sms")return `سلام. در بررسی عمومی ${l.name} یک فرصت مشخص دیدیم: ${l.issue} اگر مایل باشید گزارش کوتاه رایگان ارسال می‌کنیم. برای عدم دریافت پیام اطلاع دهید.`;if(channel==="telegram")return `سلام وقت بخیر. درباره حضور دیجیتال ${l.name} یک بررسی عمومی انجام دادیم. یافته اصلی: ${finding}.\n\nپیشنهاد: ${l.plan}\n\n${ask}`;if(channel==="divar")return `سلام وقت بخیر. درباره حضور آنلاین مجموعه شما یک بررسی عمومی انجام دادیم و ${finding}. اگر مایل باشید یک گزارش کوتاه و بدون تعهد ارسال می‌کنیم. در صورت عدم تمایل پیام دیگری نمی‌فرستیم.`;if(tone==="executive")return `سلام وقت بخیر. در بررسی عمومی ${l.name}، مهم‌ترین فرصت را این مورد دیدیم: ${l.issue}\n\nپیشنهاد: ${l.plan}\n\n${ask}`;return `سلام وقت بخیر. در بررسی عمومی وب‌سایت و حضور جست‌وجویی ${l.name}، ${finding}.\n\nبه‌نظر می‌رسد فرصت اصلی، ${l.issue} باشد. پیشنهاد ما برای ۹۰ روز نخست: ${l.plan}\n\n${ask}`}
function generateMessage(){const l=leads.find(x=>x.id===$("#outreachLead").value);if(!l)return;let msg=messageFor(l,selectedChannel,$("#tone").value);if(currentPdfShareUrl)msg+=`\n\nدانلود پیشنهاد PDF:\n${currentPdfShareUrl}`;else if($("#attachPdfCheck").checked&&["whatsapp","telegram","bale","rubika","soroush","eitaa","email"].includes(selectedChannel))msg+="\n\nفایل پیشنهاد PDF با لوگو و مشخصات مجری برای بررسی آماده است.";const a=activeAgency();msg+=`\n\n${a.name} | ${a.phone||""}\n${a.website||""}`;$("#messageBox").textContent=msg;$("#messageChars").textContent=`${fa(msg.length)} نویسه`;$("#messageSubject").value=`یک فرصت قابل‌اندازه‌گیری برای ${l.name}`}
