$("#generateMessage").onclick=generateMessage;$("#attachPdfCheck").onchange=generateMessage;$("#messageBox").oninput=()=>{$("#messageChars").textContent=`${fa($("#messageBox").textContent.length)} نویسه`};$("#copyMessage").onclick=()=>copyText($("#messageBox").textContent);$("#markContacted").onclick=()=>{const l=leads.find(x=>x.id===$("#outreachLead").value);if(l){l.contactedAt=new Date().toISOString();save();toast("تماس در پرونده محلی ثبت شد.")}};
function validateManualContact(){if(!$("#approvalCheck").checked||!$("#senderAuthCheck").checked)throw new Error("متن و مجوز نمایندگی را تأیید کنید.");if(!$("#consentCheck").checked)throw new Error("رضایت یا گفت‌وگوی خدماتی باید تأیید شود.");const phone=$("#recipient").value.replace(/\D/g,"");if(phone.length<8)throw new Error("شماره WhatsApp معتبر وارد کنید.");return phone}
function openWhatsApp(mode){try{const phone=validateManualContact(),text=encodeURIComponent($("#messageBox").textContent.trim()),url=mode==="desktop"?`https://web.whatsapp.com/send?phone=${phone}&text=${text}`:`whatsapp://send?phone=${phone}&text=${text}`;window.open(url,"_blank","noopener");showSendStatus(mode==="desktop"?"WhatsApp Web در تب جدید باز شد. PDF دانلودشده را به‌صورت دستی پیوست کنید.":"درخواست بازکردن برنامه WhatsApp ارسال شد. PDF دانلودشده را پیوست کنید.",true)}catch(e){showSendStatus(e.message,false)}}
async function openChannelWeb(){if(!$("#approvalCheck").checked||!$("#senderAuthCheck").checked||!$("#consentCheck").checked)return showSendStatus("رضایت، تأیید انسانی و مجوز نمایندگی برای انتقال به نسخه وب الزامی است.",false);const url=(integrations.webApps||{})[selectedChannel];if(!url)return showSendStatus("لینک نسخه وب برای این کانال تنظیم نشده است.",false);await copyText($("#messageBox").textContent);window.open(url,"_blank","noopener");showSendStatus("متن کپی و نسخه وب رسمی باز شد. گیرنده را انتخاب، متن را Paste و PDF دانلودشده را پیوست کنید.",true)}
async function createPdfShareLink(){
  const p=currentPayload();
  if(!p.senderAuthorized)return showSendStatus("برای ساخت لینک، مجوز استفاده از نام و لوگوی شرکت را تأیید کنید.",false);
  if(!apiLive)return showSendStatus("ساخت لینک PDF به سرور فعال نیاز دارد. برنامه را با server.py یا Hugging Face Space اجرا کنید.",false);
  const button=$("#createPdfShareLink");button.disabled=true;button.textContent="در حال ساخت لینک…";
  try{
    const response=await fetch("/api/proposal-link",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p.proposal)});
    const result=await response.json();if(!response.ok||!result.ok)throw new Error(result.error||"ساخت لینک ناموفق بود.");
    currentPdfShareUrl=result.url;$("#pdfShareUrl").value=result.url;$("#pdfLinkBox").classList.add("show");
    const expires=new Date(result.expiresAt*1000);$("#pdfLinkExpiry").textContent=`انقضا: ${expires.toLocaleString("fa-IR")} — لینک موقت است و با ری‌استارت فضای رایگان ممکن است زودتر از بین برود.`;
    generateMessage();await copyText(result.url);showSendStatus("لینک PDF ساخته، به پیام اضافه و در کلیپ‌بورد کپی شد. اکنون WhatsApp را باز کنید.",true);
  }catch(error){showSendStatus(error.message,false)}finally{button.disabled=false;button.textContent="ساخت لینک دانلود PDF"}
}
async function downloadOutreachPdf(){const p=currentPayload();if(!p.senderAuthorized)return showSendStatus("مجوز استفاده از نام و لوگوی شرکت را تأیید کنید.",false);if(!apiLive||integrations.proposalPdfMode!=="direct-download"){go("proposals");$("#proposalLead").value=p.leadId;$("#proposalAgencyProfile").value=activeAgencyId;renderProposal();toast("PDF مستقیم در دسترس نیست؛ از Print / Save as PDF استفاده کنید.");return}const b=$("#downloadPdfForWhatsApp");b.disabled=true;try{const r=await fetch("/api/proposal-pdf",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p.proposal)});if(!r.ok){const j=await r.json();throw new Error(j.error||"خطای PDF")}const blob=await r.blob(),a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=`proposal-${p.leadId}.pdf`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1500);showSendStatus("PDF دانلود شد. اکنون WhatsApp موبایل یا Web را باز و فایل را پیوست کنید.",true)}catch(e){showSendStatus(e.message,false)}finally{b.disabled=false}}
$("#openWhatsAppMobile").onclick=()=>openWhatsApp("mobile");$("#openWhatsAppDesktop").onclick=()=>openWhatsApp("desktop");$("#openChannelWeb").onclick=openChannelWeb;$("#createPdfShareLink").onclick=createPdfShareLink;$("#downloadPdfForWhatsApp").onclick=downloadOutreachPdf;$("#copyPdfLink").onclick=()=>copyText($("#pdfShareUrl").value);$("#openPdfLink").onclick=()=>{const url=$("#pdfShareUrl").value;if(url)window.open(url,"_blank","noopener")};
function currentPayload(){const l=leads.find(x=>x.id===$("#outreachLead").value),a=activeAgency(),d=proposalDefaults(l);return{channel:selectedChannel,recipient:$("#recipient").value.trim(),message:$("#messageBox").textContent.trim(),subject:$("#messageSubject").value.trim(),leadId:l?.id||"",consent:$("#consentCheck").checked,approved:$("#approvalCheck").checked,senderAuthorized:$("#senderAuthCheck").checked,attachProposalPdf:$("#attachPdfCheck").checked,doNotContact:!!l?.doNotContact,sender:{id:a.id,name:a.name,phone:a.phone,website:a.website},proposal:{agency:a.name,agencyProfile:{name:a.name,address:a.address,phone:a.phone,website:a.website,email:a.email,whatsapp:a.whatsapp,hours:a.hours,logoData:a.logoData||"",logoUrl:a.logoUrl||""},validity:"۱۴ روز",setup:d[0],monthly:d[1],media:d[2],duration:d[3],lead:{id:l.id,name:l.name,seo:l.seo,opportunity:opportunity(l),priority:priority(l),tech:l.tech,issue:l.issue,plan:l.plan,target:l.target,package:pkg(l)}}}}
function showSendStatus(text,ok){const s=$("#sendStatus");s.textContent=text;s.className=`send-status show ${ok?"ok":"err"}`}
async function sendPayload(payload){if(!payload.recipient)throw new Error("گیرنده را وارد کنید.");if(!payload.consent)throw new Error("رضایت یا گفت‌وگوی خدماتی باید تأیید شود.");if(!payload.approved)throw new Error("تأیید انسانی متن و گیرنده الزامی است.");if(!payload.senderAuthorized)throw new Error("مجوز نمایندگی شرکت ارسال‌کننده باید تأیید شود.");if(!apiLive)return{ok:true,sent:false,dryRun:true,status:"simulated",message:"پیش‌نمایش آفلاین: پیام اعتبارسنجی شد اما ارسال نشد."};const r=await fetch("/api/send",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});const j=await r.json();if(!j.ok)throw new Error(j.error||"ارسال ناموفق بود.");return j}
async function sendCurrent(){const p=currentPayload();try{$("#sendNow").disabled=true;showSendStatus("در حال اعتبارسنجی و ارسال…",true);const r=await sendPayload(p);showSendStatus(r.sent?"پیام و فایل PDF با موفقیت از Provider رسمی ارسال شد.":(r.message||"پیام در حالت Dry Run شبیه‌سازی شد.")+(r.attachmentReady?" فایل PDF همراه لوگو نیز با موفقیت تولید شد.":"")+(r.manualAttachmentRequired?" این کانال به پیوست دستی PDF در نسخه وب نیاز دارد.":""),true);const l=leads.find(x=>x.id===p.leadId);if(l){l.lastSend={time:new Date().toISOString(),channel:p.channel,status:r.status};save()}}catch(e){showSendStatus(e.message,false)}finally{$("#sendNow").disabled=false}}
function addToQueue(){const p=currentPayload();if(!p.recipient)return toast("گیرنده را وارد کنید.");if(!p.consent||!p.approved||!p.senderAuthorized)return toast("رضایت، تأیید انسانی و مجوز نمایندگی برای صف الزامی است.");let when=Date.now();if($("#sendTiming").value==="scheduled"){when=new Date($("#scheduleAt").value).getTime();if(!Number.isFinite(when)||when<Date.now())return toast("زمان معتبر آینده را انتخاب کنید.")}sendQueue.push({...p,id:"send-"+Date.now(),scheduledAt:when,status:"pending"});saveSendQueue();renderSendQueue();toast("پیام تأییدشده به صف اضافه شد.")}
function renderSendQueue(){const box=$("#sendQueue");if(!box)return;if(!sendQueue.length){box.innerHTML='<div class="empty">صف ارسال خالی است.</div>';return}box.innerHTML=sendQueue.map(x=>{const l=leads.find(y=>y.id===x.leadId);return`<div class="campaign-item"><div><strong>${esc(l?.name||"لید حذف‌شده")} · ${esc(x.channel)}</strong><p>${new Date(x.scheduledAt).toLocaleString("fa-IR")} · گیرنده ${esc(String(x.recipient).slice(0,4))}… · ${esc(x.status)}</p></div><span class="status ${x.status==="sent"?"done":x.status==="error"?"error":"running"}">${x.status==="pending"?"در صف":x.status==="sent"?"ارسال‌شده":x.status==="simulated"?"Dry Run":"خطا"}</span></div>`}).join("")}
async function runSendQueue(){const due=sendQueue.filter(x=>x.status==="pending"&&x.scheduledAt<=Date.now());if(!due.length)return toast("پیام آماده‌ای برای اجرا وجود ندارد.");$("#runSendQueue").disabled=true;for(const item of due){try{const r=await sendPayload(item);item.status=r.sent?"sent":"simulated";item.result=r.status}catch(e){item.status="error";item.result=e.message}saveSendQueue();renderSendQueue();await new Promise(r=>setTimeout(r,450))}$("#runSendQueue").disabled=false;toast("صف آماده پردازش شد.")}
function renderIntegrations(){const names={whatsapp:"WhatsApp",telegram:"Telegram",bale:"Bale",rubika:"Rubika",soroush:"Soroush+",eitaa:"Eitaa",email:"Email",sms:"SMS",divar:"Divar Chat"};$("#integrationGrid").innerHTML=Object.keys(names).map(k=>`<div class="integration"><b>${names[k]}</b><small>${integrations.providers[k]?"Provider روی سرور تنظیم شده است":k==="divar"?"Manual handoff؛ وب‌هوک شریک رسمی تنظیم نشده":"نیازمند متغیرهای محیطی سرور"}</small><span class="source-state ${integrations.providers[k]?"ready":""}" style="display:inline-block;margin-top:8px">${integrations.providers[k]?"آماده":"تنظیم نشده"}</span></div>`).join("");$("#sendModeLabel").textContent=integrations.sendEnabled&&!integrations.dryRun?"ارسال واقعی فعال":"حالت امن: Dry Run";$("#manualHandoff").style.display=selectedChannel==="divar"&&!integrations.providers.divar?"inline-flex":"none"}
$("#sendNow").onclick=sendCurrent;$("#addQueue").onclick=addToQueue;$("#runSendQueue").onclick=runSendQueue;$("#clearSendQueue").onclick=()=>{if(confirm("صف ارسال پاک شود؟")){sendQueue=[];saveSendQueue();renderSendQueue()}};$("#manualHandoff").onclick=async()=>{if(!$("#consentCheck").checked||!$("#approvalCheck").checked||!$("#senderAuthCheck").checked)return showSendStatus("برای انتقال دستی نیز رضایت، تأیید انسانی و مجوز نمایندگی الزامی است.",false);await copyText($("#messageBox").textContent);window.open("https://divar.ir/","_blank","noopener");showSendStatus("متن کپی شد. پیام را فقط در گفت‌وگوی مجاز و مرتبط Divar به‌صورت دستی ارسال کنید.",true)};
setInterval(()=>{if(sendQueue.some(x=>x.status==="pending"&&x.scheduledAt<=Date.now()))runSendQueue()},30000);
async function copyText(t){try{await navigator.clipboard.writeText(t);toast("کپی شد.")}catch(e){const a=document.createElement("textarea");a.value=t;document.body.append(a);a.select();document.execCommand("copy");a.remove();toast("کپی شد.")}}
function exportData(type="json"){if(type==="json")download("clinic-signal-leads.json",JSON.stringify(leads,null,2),"application/json");else{const cols=["name","scale","seo","opportunity","priority","website","phone","email","whatsapp","tags","area","services","issue","package"];const rows=[cols.join(","),...leads.map(l=>[l.name,l.scale,l.seo,opportunity(l),priority(l),l.website,l.phone,l.email,l.whatsapp,(l.tags||[]).join("|"),l.area,l.services,l.issue,pkg(l)].map(x=>'"'+String(x??"").replaceAll('"','""')+'"').join(","))];download("clinic-signal-leads.csv","\ufeff"+rows.join("\n"),"text/csv")}}
function download(name,text,type){const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([text],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
$("#exportTop").onclick=()=>exportData("csv");$("#exportJson").onclick=$("#downloadBackup").onclick=()=>exportData("json");$("#importBtn").onclick=()=>$("#importFile").click();$("#importFile").onchange=e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=()=>{try{const x=JSON.parse(r.result);if(!Array.isArray(x))throw 0;leads=x;save();renderAll();toast("داده وارد شد.")}catch(err){toast("فایل JSON معتبر نیست.")}};r.readAsText(f)};
