function showFatalError(error){
  console.error(error);
  const box=document.createElement("div");
  box.style.cssText="position:fixed;inset:auto 20px 20px 20px;z-index:9999;background:#7f1d1d;color:white;padding:14px 18px;border-radius:12px;font:13px Tahoma;direction:rtl";
  box.textContent="خطای رابط کاربری: "+(error?.message||String(error))+" — صفحه را تازه‌سازی کنید یا داده‌های محلی را پاک کنید.";
  document.body.appendChild(box);
}
window.addEventListener("error",event=>showFatalError(event.error||event.message));
window.addEventListener("unhandledrejection",event=>showFatalError(event.reason));
try{renderAll();applyUiLanguage(uiLanguage);detectApi()}catch(error){showFatalError(error)}
